// Hunt 1 - File Hash IoC Match (ZIP, EXE, DLL, Renamed Python)
// MITRE: T1204.002 - User Execution: Malicious File
let malicious_hashes = dynamic([
    "35efc4b75a1d70c38513b4dfe549da417aaa476bf7e9ebd00265aaa8c7295870",  // ZIP lure (SHA256)
    "1539dab6099d860add8330bf2a008a4b6dc05c71f7b4439aebf431e034e5b6ff",  // Notice of Alleged Violation.exe / ADNotificationManager.exe (SHA256)
    "ac591adea9a2305f9be6ae430996afd9b7432116f381b638014a0886a99c6287",  // urlmon.dll shellcode loader (SHA256)
    "f4532fc1e5d53a732fcc883f7125ceb06b985048"                             // svchost.exe (renamed python.exe) (SHA1)
]);
DeviceFileEvents
| where Timestamp {timeframe}
| where SHA256 in (malicious_hashes) or SHA1 in (malicious_hashes)
| project-reorder Timestamp, DeviceName, FileName, FolderPath, SHA256, SHA1, InitiatingProcessCommandLine, InitiatingProcessAccountName
| sort by Timestamp desc

// Hunt 2 - Network IoC Match (C2 Domains and IPs)
// MITRE: T1071.001 - Application Layer Protocol: Web Protocols
// MITRE: T1102 - Web Service
let malicious_domains = dynamic([
    "quickdocshare.com",
    "bestshoppingday.com",
    "bestshopingday.com",
    "bestsaleshoppingday.com",
    "eideasrl.it"
]);
let malicious_ips = dynamic([
    "166.0.184.127",
    "64.40.154.96"
]);
let malicious_subdomains = dynamic([
    "dq.bestshoppingday.com",
    "logs.bestshopingday.com",
    "mh.bestshopingday.com",
    "logs.bestsaleshoppingday.com"
]);
DeviceNetworkEvents
| where Timestamp {timeframe}
| where RemoteUrl has_any (malicious_domains)
    or RemoteIP in (malicious_ips)
    or RemoteUrl has_any (malicious_subdomains)
| project-reorder Timestamp, DeviceName, InitiatingProcessFileName, InitiatingProcessCommandLine, RemoteIP, RemoteUrl, RemotePort, ActionType
| sort by Timestamp desc

// Hunt 4 - Copyright/IP Lure EXE Execution from Downloads
// MITRE: T1566.002 - Phishing: Spearphishing Link
// MITRE: T1204.002 - User Execution: Malicious File
// Detects execution of EXE files from Downloads directory with copyright/IP-themed names
DeviceProcessEvents
| where Timestamp {timeframe}
| where FolderPath has "Downloads"
    and FileName endswith ".exe"
    and (
        ProcessCommandLine has_any ("Copyright", "Violation", "Intellectual", "Property", "Urheberrecht", "Versto", "Rechtsverletzung", "Notice", "Alleged", "Dokumentation")
        or FolderPath has_any ("Copyright", "Violation", "Intellectual", "Property", "Notice", "Alleged")
    )
| project-reorder Timestamp, DeviceName, AccountName, FileName, FolderPath, ProcessCommandLine, SHA256, InitiatingProcessFileName
| sort by Timestamp desc

// Hunt 5 - Suspicious curl Usage for Encrypted Payload + Key Retrieval
// MITRE: T1105 - Ingress Tool Transfer
// MITRE: T1071.001 - Application Layer Protocol: Web Protocols
DeviceProcessEvents
| where Timestamp {timeframe}
| where FileName =~ "curl.exe"
    and (
        ProcessCommandLine has "meow_meow"
        or (ProcessCommandLine has "-A" and ProcessCommandLine has "-s" and ProcessCommandLine has "-k" and ProcessCommandLine has "-L")
        or (ProcessCommandLine has "-s" and ProcessCommandLine has "-k" and ProcessCommandLine has "invoice.pdf")
        or (ProcessCommandLine has "DQ" and ProcessCommandLine has "key")
    )
| project-reorder Timestamp, DeviceName, InitiatingProcessAccountName, ProcessCommandLine, InitiatingProcessCommandLine, InitiatingProcessFileName, SHA256
| sort by Timestamp desc

// Hunt 6 - Renamed WinRAR (PNG Extension) Extracting Password-Protected Archives
// MITRE: T1036.005 - Masquerading / T1140 - Deobfuscate Files
DeviceProcessEvents
| where Timestamp {timeframe}
| where FileName endswith ".png"
    and (
        (ProcessCommandLine has " x " and ProcessCommandLine has "-p")
        or ProcessCommandLine has "invoice.pdf"
        or (ProcessCommandLine has "Users" and ProcessCommandLine has "Public")
    )
| project-reorder Timestamp, DeviceName, InitiatingProcessAccountName, FileName, FolderPath, ProcessCommandLine, SHA256, InitiatingProcessCommandLine
| sort by Timestamp desc

// Hunt 7 - Renamed Python.exe (svchost.exe) Running PDF Loader from Public Path
// MITRE: T1036.003 - Masquerading: Rename System Utilities
// MITRE: T1059.006 - Command and Scripting Interpreter: Python
// Detects svchost.exe executing from non-standard paths (not System32/SysWOW64)
DeviceProcessEvents
| where Timestamp {timeframe}
| where FileName =~ "svchost.exe"
    and not (FolderPath startswith "C:\\Windows\\System32" or FolderPath startswith "C:\\Windows\\SysWOW64")
| where ProcessCommandLine has_any ("instructions.pdf", ".pdf", "-c", "exec(", "base64")
    or FolderPath has "Public"
| project-reorder Timestamp, DeviceName, AccountName, FileName, FolderPath, ProcessCommandLine, SHA256, InitiatingProcessFileName
| sort by Timestamp desc

// Hunt 9 - Silent AV Enumeration via PowerShell WMI SecurityCenter2
// MITRE: T1518.001 - Security Software Discovery
// MITRE: T1059.001 - Command and Scripting Interpreter: PowerShell
DeviceProcessEvents
| where Timestamp {timeframe}
| where FileName =~ "powershell.exe"
    and ProcessCommandLine has "SecurityCenter2"
    and ProcessCommandLine has "AntivirusProduct"
    and (
        ProcessCommandLine has "-NoProfile"
        or ProcessCommandLine has "-WindowStyle Hidden"
        or ProcessCommandLine has "Get-WmiObject"
    )
| project-reorder Timestamp, DeviceName, InitiatingProcessAccountName, ProcessCommandLine, InitiatingProcessFileName, InitiatingProcessCommandLine, InitiatingProcessFolderPath
| sort by Timestamp desc

// Hunt 10 - AMSI Bypass / Impairment from Non-Standard Process Paths
// MITRE: T1562.001 - Impair Defenses: Disable or Modify Tools
// Detects AMSI-related events from non-standard script hosts or from Public paths
DeviceEvents
| where Timestamp {timeframe}
| where ActionType in ("AmsiScriptDetection", "AntivirusDetection", "AntivirusScanCompleted")
    and (
        InitiatingProcessFolderPath has "Public"
        or InitiatingProcessFileName =~ "svchost.exe"
        or InitiatingProcessCommandLine has "instructions.pdf"
    )
| project-reorder Timestamp, DeviceName, ActionType, InitiatingProcessFileName, InitiatingProcessFolderPath, InitiatingProcessCommandLine, AdditionalFields
| sort by Timestamp desc

// Hunt 11 - Python Runtime Files Dropped in Fake Windows Directory (C:\Users\Public\Windows)
// MITRE: T1564.001 - Hide Artifacts: Hidden Files and Directories
// MITRE: T1059.006 - Command and Scripting Interpreter: Python
// Detects Python runtime files extracted into a fake Windows system directory
let python_artifacts = dynamic([
    "python314.dll", "_ctypes.pyd", "libffi-8.dll", "_hashlib.pyd",
    "libcrypto-3.dll", "_socket.pyd", "_ssl.pyd", "libssl-3.dll",
    "_bz2.pyd", "_lzma.pyd", "_zstd.pyd", "svchost.exe", "instructions.pdf"
]);
DeviceFileEvents
| where Timestamp {timeframe}
| where FolderPath startswith "C:\\Users\\Public\\Windows"
    and (
        FileName in~ (python_artifacts)
        or FileName endswith ".pyd"
        or FileName endswith ".dll"
    )
| project-reorder Timestamp, DeviceName, ActionType, FileName, FolderPath, SHA256, InitiatingProcessFileName, InitiatingProcessCommandLine
| sort by Timestamp desc

// Hunt 12 - Chrome Launched with Sandbox-Disabled Flags by Suspicious Parent (Browser Credential Harvesting)
// MITRE: T1185 - Browser Session Hijacking
// MITRE: T1555.003 - Credentials from Password Stores: Credentials from Web Browsers
DeviceProcessEvents
| where Timestamp {timeframe}
| where FileName =~ "chrome.exe"
    and ProcessCommandLine has "--no-sandbox"
    and ProcessCommandLine has "--user-data-dir"
    and ProcessCommandLine has "Temp"
    and ProcessCommandLine has "--extension-process"
    and not (InitiatingProcessFileName in~ ("chrome.exe", "explorer.exe", "cmd.exe", "powershell.exe"))
| project-reorder Timestamp, DeviceName, InitiatingProcessAccountName, ProcessCommandLine, InitiatingProcessFileName, InitiatingProcessFolderPath, InitiatingProcessCommandLine
| sort by Timestamp desc

// Hunt 14 - CacheVersion=1337 Registry Marker (PureLog C2 Exfil Success Indicator)
// MITRE: T1112 - Modify Registry
DeviceRegistryEvents
| where Timestamp {timeframe}
| where RegistryKey has "AppModel\\StateRepository"
    and RegistryValueName =~ "CacheVersion"
    and RegistryValueData =~ "1337"
| project-reorder Timestamp, DeviceName, InitiatingProcessAccountName, RegistryKey, RegistryValueName, RegistryValueData, InitiatingProcessFileName, InitiatingProcessCommandLine
| sort by Timestamp desc

// Hunt 15 - HTTPS C2 Exfiltration from Renamed Python Loader (Public Path svchost.exe)
// MITRE: T1041 - Exfiltration Over C2 Channel
// MITRE: T1567 - Exfiltration Over Web Service
// Detects outbound HTTPS connections from the renamed python loader for data exfiltration
DeviceNetworkEvents
| where Timestamp {timeframe}
| where InitiatingProcessFileName =~ "svchost.exe"
    and InitiatingProcessFolderPath has "Public"
    and RemotePort == 443
    and ActionType == "ConnectionSuccess"
| project-reorder Timestamp, DeviceName, InitiatingProcessFileName, InitiatingProcessFolderPath, InitiatingProcessCommandLine, RemoteIP, RemoteUrl, RemotePort
| sort by Timestamp desc
